// Validate required fields from webhook body
const body = $input.first().json.body || $input.first().json;

const required = ['first_name', 'last_name', 'email', 'program_interest'];
const missing = required.filter(f => !body[f] || String(body[f]).trim() === '');

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Basic email validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  throw new Error('Invalid email address');
}

// Normalize phone (strip non-digits, keep + prefix)
let phone = body.phone || '';
if (phone) {
  phone = phone.replace(/[^\d+]/g, '');
}

// Build validated prospect object
return [{
  json: {
    first_name: String(body.first_name).trim(),
    last_name: String(body.last_name).trim(),
    email: String(body.email).trim().toLowerCase(),
    phone: phone,
    program_interest: String(body.program_interest).trim(),
    source: body.source || 'website',
    inquiry_ip_address: body.ip_address || null,
    inquiry_user_agent: body.user_agent || null,
    inquiry_submitted_at: new Date().toISOString(),
    tenant_id: '00000000-0000-0000-0000-000000000001',
    eligibility_status: 'pending',
    remarketing_eligible: true
  }
}];

// Supabase returns an array with the created record
const response = $input.first().json;
const prospect = Array.isArray(response) ? response[0] : response;

// Pass through all data plus the new prospect ID
return [{
  json: {
    prospect_id: prospect.id,
    first_name: prospect.first_name,
    last_name: prospect.last_name,
    email: prospect.email,
    phone: prospect.phone,
    program_interest: prospect.program_interest,
    inquiry_submitted_at: prospect.inquiry_submitted_at
  }
}];

